INSERT INTO category_descriptions (category_uuid, description, created_at, updated_at) VALUES
('74e2f4f4-5ed2-4039-a338-a085dfe67da8', 'Explore the latest breakthroughs in software, hardware, and emerging tech. From artificial intelligence and cybersecurity to programming trends and the gadgets shaping how we live and work, this category covers everything driving the digital world forward.', now(), now()),
('8ef57f90-5312-43ae-beaf-aa39801f1c60', 'Discover destinations near and far, from budget-friendly backpacking routes to hidden local gems. This category is packed with practical tips, city guides, and stories to help you plan your next adventure, wherever it takes you.', now(), now()),
('62f80dad-2b1f-4be0-ba41-4bb624f4665c', 'Dive into recipes, cooking techniques, and culinary traditions from around the globe. Whether you''re baking sourdough at home or exploring regional cuisines, this category celebrates everything that happens in and around the kitchen.', now(), now()),
('82770db7-d94d-4791-bfe2-858ffbc46bb5', 'Practical guidance on physical and mental well-being, covering everything from sleep and stress management to fitness routines and nutrition. This category helps you build habits that support a healthier, more balanced life.', now(), now()),
('370b15f9-cbb9-4b9a-8ee9-a32641e1ec35', 'Insights on entrepreneurship, personal finance, and the modern workplace. From building a brand to understanding remote work trends, this category covers the strategies and ideas shaping how businesses grow and operate.', now(), now()),
('3b7b0ad7-1dd6-411b-b065-b5dca76e2973', 'Coverage of athletic achievement, training, and the business behind the games we love. From Olympic history to marathon training and the tech transforming athletic performance, this category has it all.', now(), now());
